_ & __\r\n\'\'\'#we general use private variable,that means when ever u use double leading__\r\nour python intrepts as a special variable in order to avoid name conflict with methods and inner classes\'\'\'\r\n\'\'\'class employes():\r\n    def __init__ (self):\r\n       self.name=\"pooja\"\r\n       self.__salary=2100\r\n       self._place=\"vij\"\r\na=employes()\r\nprint(dir(a))\r\nprint(a.name)\r\n\r\nprint(a._place)\r\n#print(a.__salary)\r\nprint(a._employes__salary)\r\n\'\'\'\r\n\'\'\'\r\nclass employes():\r\n    def __init__ (self):\r\n       self.name=\"pooja\"\r\n       self.__salary=21002\r\n       self._place=\"vij\"\r\na=employes()\r\nclass employes1():\r\n    def __init__ (self):\r\n       self.name=\"jas\"\r\n       self.__salary=2100\r\n       self._place=\"vij\"\r\nb=employes1()\r\nclass employes2():\r\n    def __init__ (self):\r\n       self.name=\"ari\"\r\n       self.__salary=2100567\r\n       self._place=\"vij\"\r\nc=employes2()\r\nprint(a.name)\r\nprint(c.name)\r\n#print(c.salary)\r\n\r\nprint(a._employes__salary)\r\n\'\'\'\r\n\r\n#polymorphism\r\n\r\n#operator overloading--> same function name but different behaviour\r\n\'\'\'a=3\r\nb=4\r\nprint(a+b)\r\nprint(a.__add__(b))\r\nprint(a.__add__(6))\r\nprint(a.__sub__(2))\r\nprint(a.__mul__(2))\r\n#print(a.__div__(2))\r\nprint(a.__pow__(1))\r\nprint(a.__ge__(2))\r\nprint(a.__le__(2))\r\na=[1,2,3,4]\r\nb=[4,5,7,8]\r\nprint(a+b)\r\nprint(a.__add__(b))\r\nprint(a.__getitem__(3))\r\nprint(a.__getitem__(2))\r\na=\"codegnan\"\r\nb=\"it\"\r\nprint(a+b)\r\nprint(a.__add__(b))\r\nprint(a.__add__(\" \"+b))\r\nprint(\"pooja\".__add__(b))\r\nprint(a.__add__(\" \"+b).title())\'\'\'\r\n\r\n\r\n#operator overriding-->A child class provides its own version of a method that is already defined in the parent class\r\n\r\n\'\'\'class A():\r\n    def __init__(self,a):\r\n        self.a=a\r\n    def __add__(self,value):\r\n        return self.a*value.b\r\nclass B():\r\n    def __init__(self,b):\r\n        self.b=b\r\nx=A(4)\r\ny=B(5)\r\nprint(x+y)\r\n        \'\'\'\r\n\r\n#method overloading-->Same method name but different number/type of arguments\r\nclass new():\r\n    def sum(self,a=None,b=None,c=None):\r\n        if a!=None and b!= None and c!= None:\r\n            print(\"sum of three\",a+b+c)\r\n        elif a!=None and b!=None:\r\n            print(\"mult is two\",a*b)\r\n        else:\r\n            print(\"program is end\")\r\na=new()\r\na.sum()\r\na.sum(1,2,3)\r\na.sum(1,2)\r\n\r\n#method overridding-->A child class changes the implementation of a method that is already defined in its parent class.\r\n#Parent class method ni, Child class lo same name tho malli define cheyadam\r\n\'\'\'class animals():\r\n    def speak(self):\r\n        print(\"animal can make sounds\")\r\nclass dog():\r\n    def speak(self):\r\n        print(\"dog barks\")\r\na=animals()\r\nb=dog()\r\na.speak()\r\nb.speak()\'\'\'\r\n\r\n\'\'\'class veh():\r\n    def sounds(self):\r\n        print(\"veh can sound\")\r\nclass bus():\r\n    def sounds(self):\r\n        print(\"pai pai sounds\")\r\na=veh()\r\nb=bus()\r\na.sounds()\r\nb.sounds()\'\'\'\r\n\r\n\r\n#inheritance\r\n\r\n#single inheritance\r\n\r\n\'\'\'class rbi():#parent class\r\n    cash=100000\r\n    def available_cash(self):\r\n        #print(\"available cash\",self.cash)\r\n        print(\"available cash\",rbi.cash)\r\n\r\nclass sbi(rbi):\r\n    pass\r\nclass hdfc(rbi):\r\n    cash=50000\r\n    def new_cash(self):\r\n       #print(\"available cash id\",self.cash+self.cash)\r\n        print(\"new cash is\",self.cash+rbi.cash)\r\nc=hdfc()\r\nc.available_cash()\r\nc.new_cash()\'\'\'\r\n\r\n\'\'\'class rbi():#parent class\r\n    cash=100000\r\n    def available_cash(self):\r\n        #print(\"available cash\",self.cash)\r\n        print(\"available cash\",rbi.cash)\r\n\r\nclass sbi(rbi):\r\n    cash=2500\r\n    def newcash(self):\r\n        print(\"available cash\",self.cash+self.cash)\r\n        print(\"new cash \",self.cash+rbi.cash)\r\n    \r\n