'\'\'\r\n#privatedata\r\n\r\n\'\'\'\r\nclass parent():\r\n    __privatedata=10\r\n    def method1(self):\r\n        print(self.__privatedata)\r\nclass child(parent):\r\n    def method2(self):\r\n        print(self._parent__privatedata)\r\nobj=child()\r\nobj.method2()\r\nobj.method1()\r\nprint(obj._parent__privatedata)\'\'\'\r\n\r\n#Abstarction-> hiding unnesccery information from user is called abstraction\r\n\r\n#abstract class->if class contains one are more one abstarction method then class is called abstarct class\r\n#abstarct method->if the method is declared without implementation is called abstarct method\r\n\r\n\'\'\'class a():\r\n    def methods(self):\r\n        #pass\r\nobj=a()\r\nobj.method()\'\'\'\r\n\r\n\r\n\r\n\'\'\'class a():\r\n    def method(self):\r\n        print(\"python class\")\r\nobj=a()\r\nobj.method()\'\'\'\r\n\r\n\r\n\'\'\'from abc import ABC,abstractmethod\r\nclass a(ABC):\r\n    @abstractmethod\r\n    def method(self):\r\n        pass\r\nobj=a()\r\nobj.method()\r\n\'\'\'\r\n\r\n\'\'\'from abc import ABC,abstractmethod\r\nclass a(ABC):\r\n    @abstractmethod\r\n    def method(self):\r\n        print(\"python class\")\r\nobj=a()\r\nobj.method()\'\'\'\r\n\r\n\'\'\'\r\n\r\nfrom abc import ABC,abstractmethod\r\nclass a(ABC):\r\n    @abstractmethod\r\n    def method1(self):\r\n        pass\r\n    def method2(sel):\r\n        print(\"method2 implemented\")\r\n    @abstractmethod\r\n    def method3(self):\r\n        pass\r\nclass b(a):\r\n    def method1(self):\r\n        print(\"method1 implenented\")\r\n    def method3(self):\r\n        print(\"method3 implemented\")\r\nobj=b()\r\nobj.method1()\r\nobj.method2()\r\nobj.method3()\r\n\r\n\'\'\'\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n        \r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n